Voici un exemple amusant :

```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Erreur de fork" << std::endl;
        return 1;
    } else if (pid == 0) { // C'est le nouveau processus!
        std::cout << "Salut, c'est moi, le petit processus!" << std::endl;
        close(1); // On ferme le stdout de base
        dup2(STDIN_FILENO, 1); // On redirige le stdout vers le stdin (drôle, non?)
        std::cout << "Maintenant, tout ce que je vais dire sera considéré comme une entrée!" << std::endl;
    } else { // C'est le processus parent
        wait(NULL); // On attend que le processus fils se termine
        std::cout << "Salut, c'est le grand processus!" << std::endl;
    }
    return 0;
}
```

C'est un peu de farce, mais c'est une façon amusante de comprendre comment fonctionne la redirection des flux dans les processus C++. Joyeux coding!
